The 1.33 E-value reflects the strength needed to eliminate the point estimate, whereas the 1.24 reflects the strength needed to render the result statistically non-significant. In this case, both are small, underscoring the fragility of the finding especially  for the larger absolute all-cause MACE.        



::: {.cell}

```{.r .cell-code}
library(EValue)
library(dplyr)
library(tibble)
library(gt)
library(ggplot2)
library (patchwork)

plot_df <- data.frame(
  Outcome = c("COVID-associated ", "All-cause "),
  RR = c(0.623, 0.938),
  E_point = c(2.59, 1.33),
  E_CI = c(1.74, 1.24),
  RD = c(2.0, 23.7)   # per 10,000
)

g1 <- ggplot(plot_df, aes(x = RR, y = E_point)) +

  # vertical line between CI-limit and point E-value
  geom_segment(aes(xend = RR, y = E_CI, yend = E_point),
               linewidth = 1, color = "grey40") +

  # CI-limit (triangle)
  geom_point(aes(y = E_CI), shape = 17, size = 3, color = "black") +

  # point estimate (circle)
  geom_point(size = 3.5, color = "black") +

  # labels
  geom_text(aes(label = Outcome), nudge_x = 0.05,
            nudge_y = 0.12, size = 4) +

  # vertical reference line at RR = 1
  geom_vline(xintercept = 1, linetype = "dashed", color = "grey60") +

  labs(
    x = "Risk Ratio (closer to 1 = weaker effect)",
    y = "E-value (higher = more robust)",
    title = "MACE Effect Size vs Robustness \nto Unmeasured Confounding",
    subtitle = "Circle = point estimate; Triangle = CI-limit"
  ) +

  coord_cartesian(xlim = c(0.6, 1.0), ylim = c(1.2, 2.7)) +

  theme_minimal(base_size = 13) +
  theme(
    plot.title = element_text(face = "bold"),
    panel.grid.minor = element_blank()
  )

g2 <- ggplot(plot_df, aes(x = RR, y = E_point)) +

  geom_segment(aes(xend = RR, y = E_CI, yend = E_point),
               linewidth = 1, color = "grey40") +

  geom_point(
    aes(size = RD),   # absolute effect shown as size
    shape = 21, fill = "black", color = "black"
  ) +

  geom_point(aes(y = E_CI), shape = 17, size = 3) +

  geom_text(
    aes(label = paste0(Outcome, "\nRD=", RD)),
    nudge_x = 0.05,
    nudge_y = 0.12, size = 4
  ) +

  geom_vline(xintercept = 1, linetype = "dashed", color = "grey60") +

  scale_size(range = c(3, 8), guide = "none") +

  labs(
    x = "Risk Ratio",
    y = "E-value",
    title = "Absolute MACE Effect vs Robustness",
    subtitle = "Larger absolute effects can arise from weaker \nand more fragile relative effects"
  ) +

  coord_cartesian(xlim = c(0.6, 1.0), ylim = c(1.2, 2.7)) +

  theme_minimal(base_size = 13) +
  theme(
    plot.title = element_text(face = "bold"),
    panel.grid.minor = element_blank()
  )

g1+g2
```

